INSERT INTO public.proposals (council_slug, budget_category, title, body, author_id, score, status, labels, comment_count, created_at) VALUES ('cambridgeshire', 'central_services', 'Agency staff costs are out of control', 'We''re paying agencies 2-3x to fill roles that keep getting vacated. Fix the working conditions so permanent staff stay. It''s basic maths.', '00000000-0000-4000-a000-000000000006', 47, 'open', '{Overspend,Efficiency}', 0, '2026-03-15T20:00:29.917Z');
INSERT INTO public.proposals (council_slug, budget_category, title, body, author_id, score, status, labels, comment_count, created_at) VALUES ('cambridgeshire', 'education', 'The school transport contract needs renegotiating', 'Costs keep going up but the service keeps getting worse. Who negotiated this contract and when is it up for renewal? Publish the terms.', '00000000-0000-4000-a000-000000000011', 42, 'open', '{Overspend,Transparency}', 0, '2026-03-27T12:25:25.585Z');
INSERT INTO public.proposals (council_slug, budget_category, title, body, author_id, score, status, labels, comment_count, created_at) VALUES ('cambridgeshire', 'central_services', 'Why are council meetings still held at 2pm on a Tuesday?', 'Most people work. Move meetings to 7pm or livestream them properly so residents can actually attend and hold councillors accountable.', '00000000-0000-4000-a000-000000000012', 6, 'open', '{Transparency}', 0, '2026-03-24T09:56:31.755Z');
INSERT INTO public.proposals (council_slug, budget_category, title, body, author_id, score, status, labels, comment_count, created_at) VALUES ('cambridgeshire', 'education', 'EHCP processing is too slow — streamline the paperwork', 'Families in Cambridgeshire wait months because the process has too many handoffs. Cut the bureaucracy, not the staff. Other counties manage it faster with the same budget.', '00000000-0000-4000-a000-000000000003', 5, 'open', '{Efficiency}', 0, '2026-01-05T17:36:45.228Z');
INSERT INTO public.proposals (council_slug, budget_category, title, body, author_id, score, status, labels, comment_count, created_at) VALUES ('cambridgeshire', 'central_services', 'Sell or lease empty council buildings instead of letting them rot', 'There are council-owned buildings sitting empty costing money to maintain. Lease them to local businesses or community groups. Generate income instead of burning it.', '00000000-0000-4000-a000-000000000019', 2, 'open', '{Efficiency}', 0, '2026-01-29T08:38:57.220Z');
INSERT INTO public.proposals (council_slug, budget_category, title, body, author_id, score, status, labels, comment_count, created_at) VALUES ('derbyshire', 'transport', 'Stop patching potholes — resurface the roads properly', 'The same holes get patched every winter and fall apart by spring. Derbyshire is wasting money on temporary fixes. A proper resurfacing programme would be cheaper over 5 years.', '00000000-0000-4000-a000-000000000021', 8, 'open', '{Efficiency}', 0, '2026-01-08T21:38:01.663Z');
INSERT INTO public.proposals (council_slug, budget_category, title, body, author_id, score, status, labels, comment_count, created_at) VALUES ('derbyshire', 'central_services', 'CEO earns £191k — what are the performance targets?', 'If we''re paying this much, there should be published KPIs tied to the salary. What gets measured gets managed.', '00000000-0000-4000-a000-000000000010', 56, 'open', '{Transparency}', 0, '2026-02-25T11:15:41.245Z');
INSERT INTO public.proposals (council_slug, budget_category, title, body, author_id, score, status, labels, comment_count, created_at) VALUES ('derbyshire', 'education', 'The school transport contract needs renegotiating', 'Costs keep going up but the service keeps getting worse. Who negotiated this contract and when is it up for renewal? Publish the terms.', '00000000-0000-4000-a000-000000000009', 6, 'open', '{Overspend,Transparency}', 0, '2026-01-08T19:34:04.582Z');
INSERT INTO public.proposals (council_slug, budget_category, title, body, author_id, score, status, labels, comment_count, created_at) VALUES ('derbyshire', 'transport', 'Enforce the 20mph zone outside schools — it''s pointless without cameras', 'The signs are there but nobody follows them. One camera would pay for itself in fines and actually keep kids safe.', '00000000-0000-4000-a000-000000000003', 24, 'open', '{Efficiency}', 0, '2026-03-13T01:13:45.508Z');
INSERT INTO public.proposals (council_slug, budget_category, title, body, author_id, score, status, labels, comment_count, created_at) VALUES ('derbyshire', 'education', 'EHCP processing is too slow — streamline the paperwork', 'Families in Derbyshire wait months because the process has too many handoffs. Cut the bureaucracy, not the staff. Other counties manage it faster with the same budget.', '00000000-0000-4000-a000-000000000011', 8, 'open', '{Efficiency}', 0, '2026-03-10T00:33:37.992Z');
