INSERT INTO public.proposals (council_slug, budget_category, title, body, author_id, score, status, labels, comment_count, created_at) VALUES ('devon', 'childrens_social_care', 'Children''s care placements — why are we paying private providers so much?', 'The council is spending millions on private children''s home placements. In-house provision would be a fraction of the cost. What''s the plan to bring this back in?', '00000000-0000-4000-a000-000000000002', 19, 'open', '{Overspend,Efficiency}', 0, '2026-03-02T02:22:50.586Z');
INSERT INTO public.proposals (council_slug, budget_category, title, body, author_id, score, status, labels, comment_count, created_at) VALUES ('east-sussex', 'central_services', 'How much is spent on consultants vs permanent staff?', 'I''d bet we''re paying double for consultants to do work that permanent employees could do. Publish the numbers and justify it.', '00000000-0000-4000-a000-000000000005', 35, 'open', '{Transparency,Efficiency}', 0, '2026-02-05T01:10:29.161Z');
