INSERT INTO public.proposals (council_slug, budget_category, title, body, author_id, score, status, labels, comment_count, created_at) VALUES ('essex', 'education', 'EHCP processing is too slow — streamline the paperwork', 'Families in Essex wait months because the process has too many handoffs. Cut the bureaucracy, not the staff. Other counties manage it faster with the same budget.', '00000000-0000-4000-a000-000000000001', 3, 'open', '{Efficiency}', 0, '2026-03-25T20:14:06.969Z');
INSERT INTO public.proposals (council_slug, budget_category, title, body, author_id, score, status, labels, comment_count, created_at) VALUES ('essex', 'education', 'The school transport contract needs renegotiating', 'Costs keep going up but the service keeps getting worse. Who negotiated this contract and when is it up for renewal? Publish the terms.', '00000000-0000-4000-a000-000000000023', 9, 'open', '{Overspend,Transparency}', 0, '2026-03-12T09:25:05.166Z');
INSERT INTO public.proposals (council_slug, budget_category, title, body, author_id, score, status, labels, comment_count, created_at) VALUES ('essex', 'central_services', 'Agency staff costs are out of control', 'We''re paying agencies 2-3x to fill roles that keep getting vacated. Fix the working conditions so permanent staff stay. It''s basic maths.', '00000000-0000-4000-a000-000000000019', 2, 'open', '{Overspend,Efficiency}', 0, '2026-01-24T20:52:26.879Z');
