INSERT INTO public.proposals (council_slug, budget_category, title, body, author_id, score, status, labels, comment_count, created_at) VALUES ('staffordshire', 'central_services', 'How much is spent on consultants vs permanent staff?', 'I''d bet we''re paying double for consultants to do work that permanent employees could do. Publish the numbers and justify it.', '00000000-0000-4000-a000-000000000006', 7, 'open', '{Transparency,Efficiency}', 0, '2026-02-10T13:47:49.737Z');
INSERT INTO public.proposals (council_slug, budget_category, title, body, author_id, score, status, labels, comment_count, created_at) VALUES ('staffordshire', 'central_services', 'Agency staff costs are out of control', 'We''re paying agencies 2-3x to fill roles that keep getting vacated. Fix the working conditions so permanent staff stay. It''s basic maths.', '00000000-0000-4000-a000-000000000024', 20, 'open', '{Overspend,Efficiency}', 0, '2026-01-23T12:33:40.125Z');
INSERT INTO public.proposals (council_slug, budget_category, title, body, author_id, score, status, labels, comment_count, created_at) VALUES ('staffordshire', 'childrens_social_care', 'Children''s care placements — why are we paying private providers so much?', 'The council is spending millions on private children''s home placements. In-house provision would be a fraction of the cost. What''s the plan to bring this back in?', '00000000-0000-4000-a000-000000000011', 27, 'open', '{Overspend,Efficiency}', 0, '2026-01-21T20:32:41.254Z');
INSERT INTO public.proposals (council_slug, budget_category, title, body, author_id, score, status, labels, comment_count, created_at) VALUES ('suffolk', 'transport', 'Enforce the 20mph zone outside schools — it''s pointless without cameras', 'The signs are there but nobody follows them. One camera would pay for itself in fines and actually keep kids safe.', '00000000-0000-4000-a000-000000000001', 6, 'open', '{Efficiency}', 0, '2026-03-03T01:29:03.333Z');
INSERT INTO public.proposals (council_slug, budget_category, title, body, author_id, score, status, labels, comment_count, created_at) VALUES ('suffolk', 'central_services', 'CEO earns £198k — what are the performance targets?', 'If we''re paying this much, there should be published KPIs tied to the salary. What gets measured gets managed.', '00000000-0000-4000-a000-000000000012', 37, 'open', '{Transparency}', 0, '2026-01-13T04:17:32.403Z');
INSERT INTO public.proposals (council_slug, budget_category, title, body, author_id, score, status, labels, comment_count, created_at) VALUES ('suffolk', 'central_services', 'How much is spent on consultants vs permanent staff?', 'I''d bet we''re paying double for consultants to do work that permanent employees could do. Publish the numbers and justify it.', '00000000-0000-4000-a000-000000000018', 6, 'open', '{Transparency,Efficiency}', 0, '2026-02-09T07:03:50.103Z');
