INSERT INTO public.proposals (council_slug, budget_category, title, body, author_id, score, status, labels, comment_count, created_at) VALUES ('barking-and-dagenham', 'environmental', 'Graffiti removal takes months — give residents paint', 'If the council can''t remove graffiti within a week, give residents and businesses matching paint to do it themselves. Cheaper and faster.', '00000000-0000-4000-a000-000000000019', 1, 'open', '{Efficiency}', 0, '2026-02-22T06:29:36.628Z');
INSERT INTO public.proposals (council_slug, budget_category, title, body, author_id, score, status, labels, comment_count, created_at) VALUES ('barking-and-dagenham', 'housing', 'Empty council-owned properties should be let, not left to rot', 'Flats sitting empty while families are in temporary accommodation. Even a basic refurb and let would save money vs hotels.', '00000000-0000-4000-a000-000000000018', 26, 'open', '{Efficiency}', 0, '2026-02-07T17:03:10.762Z');
INSERT INTO public.proposals (council_slug, budget_category, title, body, author_id, score, status, labels, comment_count, created_at) VALUES ('barking-and-dagenham', 'transport', 'Pavement parking enforcement is a joke', 'Cars park on pavements blocking pushchairs and wheelchairs. Nobody enforces it. One warden doing regular rounds would fix this and generate fine revenue.', '00000000-0000-4000-a000-000000000017', 3, 'open', '{Efficiency}', 0, '2026-03-21T02:12:59.679Z');
INSERT INTO public.proposals (council_slug, budget_category, title, body, author_id, score, status, labels, comment_count, created_at) VALUES ('barking-and-dagenham', 'housing', 'Temp accommodation in hotels costs more than building homes', 'The council spends millions on B&Bs for families. That money would be better used buying or building permanent housing. Publish the total hotel spend.', '00000000-0000-4000-a000-000000000015', 4, 'open', '{Overspend,Efficiency}', 0, '2026-01-20T23:42:54.891Z');
INSERT INTO public.proposals (council_slug, budget_category, title, body, author_id, score, status, labels, comment_count, created_at) VALUES ('barking-and-dagenham', 'environmental', 'Simplify the recycling — different rules on every estate', 'Nobody knows which bin is which because every estate has different rules. Standardise it borough-wide. Confusion = contamination = wasted money.', '00000000-0000-4000-a000-000000000022', 10, 'open', '{Efficiency}', 0, '2026-03-05T06:03:51.609Z');
