INSERT INTO public.proposals (council_slug, budget_category, title, body, author_id, score, status, labels, comment_count, created_at) VALUES ('camden', 'central_services', 'CEO earns £232k — what are the performance targets?', 'If we''re paying this much, there should be published KPIs tied to the salary. What gets measured gets managed.', '00000000-0000-4000-a000-000000000011', 2, 'open', '{Transparency}', 0, '2026-01-31T06:53:22.769Z');
INSERT INTO public.proposals (council_slug, budget_category, title, body, author_id, score, status, labels, comment_count, created_at) VALUES ('camden', 'central_services', 'How much is spent on consultants vs permanent staff?', 'I''d bet we''re paying double for consultants to do work that permanent employees could do. Publish the numbers and justify it.', '00000000-0000-4000-a000-000000000025', 36, 'open', '{Transparency,Efficiency}', 0, '2026-03-23T00:35:48.611Z');
INSERT INTO public.proposals (council_slug, budget_category, title, body, author_id, score, status, labels, comment_count, created_at) VALUES ('city-of-london', 'environmental', 'Street cleaning schedule doesn''t match when streets are actually dirty', 'Cleaners come Monday morning. The mess is from the weekend. Move the schedule to Sunday night or early Monday.', '00000000-0000-4000-a000-000000000013', 41, 'open', '{Efficiency}', 0, '2026-03-01T03:03:14.399Z');
INSERT INTO public.proposals (council_slug, budget_category, title, body, author_id, score, status, labels, comment_count, created_at) VALUES ('city-of-london', 'central_services', 'CEO earns £362k — what are the performance targets?', 'If we''re paying this much, there should be published KPIs tied to the salary. What gets measured gets managed.', '00000000-0000-4000-a000-000000000008', 47, 'open', '{Transparency}', 0, '2026-03-14T11:47:25.247Z');
INSERT INTO public.proposals (council_slug, budget_category, title, body, author_id, score, status, labels, comment_count, created_at) VALUES ('city-of-london', 'environmental', 'Graffiti removal takes months — give residents paint', 'If the council can''t remove graffiti within a week, give residents and businesses matching paint to do it themselves. Cheaper and faster.', '00000000-0000-4000-a000-000000000025', 110, 'open', '{Efficiency}', 0, '2026-02-21T01:25:38.364Z');
