INSERT INTO public.proposals (council_slug, budget_category, title, body, author_id, score, status, labels, comment_count, created_at) VALUES ('hounslow', 'environmental', 'Simplify the recycling — different rules on every estate', 'Nobody knows which bin is which because every estate has different rules. Standardise it borough-wide. Confusion = contamination = wasted money.', '00000000-0000-4000-a000-000000000006', 10, 'open', '{Efficiency}', 0, '2026-01-06T11:58:18.421Z');
