INSERT INTO public.proposals (council_slug, budget_category, title, body, author_id, score, status, labels, comment_count, created_at) VALUES ('sutton', 'environmental', 'Street cleaning schedule doesn''t match when streets are actually dirty', 'Cleaners come Monday morning. The mess is from the weekend. Move the schedule to Sunday night or early Monday.', '00000000-0000-4000-a000-000000000012', 3, 'open', '{Efficiency}', 0, '2026-03-04T11:43:52.992Z');
INSERT INTO public.proposals (council_slug, budget_category, title, body, author_id, score, status, labels, comment_count, created_at) VALUES ('sutton', 'central_services', 'How much is spent on consultants vs permanent staff?', 'I''d bet we''re paying double for consultants to do work that permanent employees could do. Publish the numbers and justify it.', '00000000-0000-4000-a000-000000000001', 54, 'open', '{Transparency,Efficiency}', 0, '2026-01-25T16:24:08.836Z');
INSERT INTO public.proposals (council_slug, budget_category, title, body, author_id, score, status, labels, comment_count, created_at) VALUES ('sutton', 'planning', 'Planning permission for small businesses takes too long', 'Want to open a cafe? That''ll be 4 months and £2k in fees. No wonder high streets are dying. Fast-track applications under a certain size.', '00000000-0000-4000-a000-000000000011', 13, 'open', '{Efficiency}', 0, '2026-02-13T11:34:58.422Z');
