INSERT INTO public.proposals (council_slug, budget_category, title, body, author_id, score, status, labels, comment_count, created_at) VALUES ('rochdale', 'central_services', 'Sell the council''s empty office buildings', 'Since hybrid working there are council offices sitting half-empty. Consolidate into fewer buildings and sell the rest. That''s real savings.', '00000000-0000-4000-a000-000000000021', 23, 'open', '{Efficiency}', 0, '2026-01-12T18:20:10.464Z');
INSERT INTO public.proposals (council_slug, budget_category, title, body, author_id, score, status, labels, comment_count, created_at) VALUES ('rochdale', 'transport', 'The bus timetable hasn''t adapted to hybrid working', 'Buses are empty at 7am but rammed at 10am. Adjust the schedule to how people actually live and work now.', '00000000-0000-4000-a000-000000000019', 21, 'open', '{Efficiency}', 0, '2026-03-07T08:44:23.884Z');
