INSERT INTO public.proposals (council_slug, budget_category, title, body, author_id, score, status, labels, comment_count, created_at) VALUES ('tameside', 'transport', 'The bus timetable hasn''t adapted to hybrid working', 'Buses are empty at 7am but rammed at 10am. Adjust the schedule to how people actually live and work now.', '00000000-0000-4000-a000-000000000010', 4, 'open', '{Efficiency}', 0, '2026-02-04T18:28:55.689Z');
INSERT INTO public.proposals (council_slug, budget_category, title, body, author_id, score, status, labels, comment_count, created_at) VALUES ('tameside', 'central_services', 'Why are council meetings still held at 2pm on a Tuesday?', 'Most people work. Move meetings to 7pm or livestream them properly so residents can actually attend and hold councillors accountable.', '00000000-0000-4000-a000-000000000023', 14, 'open', '{Transparency}', 0, '2026-01-24T17:35:29.948Z');
