INSERT INTO public.proposals (council_slug, budget_category, title, body, author_id, score, status, labels, comment_count, created_at) VALUES ('bournemouth-christchurch-and-poole', 'transport', 'Stop patching potholes — resurface the roads properly', 'The same holes get patched every winter and fall apart by spring. Bournemouth, Christchurch & Poole is wasting money on temporary fixes. A proper resurfacing programme would be cheaper over 5 years.', '00000000-0000-4000-a000-000000000021', 28, 'open', '{Efficiency}', 0, '2026-02-18T03:25:34.936Z');
INSERT INTO public.proposals (council_slug, budget_category, title, body, author_id, score, status, labels, comment_count, created_at) VALUES ('bracknell-forest', 'central_services', 'CEO earns £204k — what are the performance targets?', 'If we''re paying this much, there should be published KPIs tied to the salary. What gets measured gets managed.', '00000000-0000-4000-a000-000000000012', 41, 'open', '{Transparency}', 0, '2026-01-29T15:01:50.722Z');
