INSERT INTO public.proposals (council_slug, budget_category, title, body, author_id, score, status, labels, comment_count, created_at) VALUES ('derby', 'planning', 'Reduce business rates for empty high street shops', 'Half the high street is empty because rates are too high. Temporary rate relief for new businesses would fill them and bring in more tax long-term.', '00000000-0000-4000-a000-000000000023', 9, 'open', '{Efficiency}', 0, '2026-03-08T23:12:25.580Z');
INSERT INTO public.proposals (council_slug, budget_category, title, body, author_id, score, status, labels, comment_count, created_at) VALUES ('dorset-ua', 'education', 'EHCP processing is too slow — streamline the paperwork', 'Families in Dorset UA wait months because the process has too many handoffs. Cut the bureaucracy, not the staff. Other counties manage it faster with the same budget.', '00000000-0000-4000-a000-000000000017', 44, 'open', '{Efficiency}', 0, '2026-02-20T18:33:28.123Z');
INSERT INTO public.proposals (council_slug, budget_category, title, body, author_id, score, status, labels, comment_count, created_at) VALUES ('dorset-ua', 'central_services', 'Agency staff costs are out of control', 'We''re paying agencies 2-3x to fill roles that keep getting vacated. Fix the working conditions so permanent staff stay. It''s basic maths.', '00000000-0000-4000-a000-000000000022', 2, 'open', '{Overspend,Efficiency}', 0, '2026-01-31T21:02:59.820Z');
INSERT INTO public.proposals (council_slug, budget_category, title, body, author_id, score, status, labels, comment_count, created_at) VALUES ('dorset-ua', 'transport', 'Stop patching potholes — resurface the roads properly', 'The same holes get patched every winter and fall apart by spring. Dorset UA is wasting money on temporary fixes. A proper resurfacing programme would be cheaper over 5 years.', '00000000-0000-4000-a000-000000000003', 6, 'open', '{Efficiency}', 0, '2026-03-18T05:52:40.780Z');
INSERT INTO public.proposals (council_slug, budget_category, title, body, author_id, score, status, labels, comment_count, created_at) VALUES ('dorset-ua', 'planning', 'Planning applications shouldn''t take 6 months', 'Local businesses can''t wait half a year for planning permission. Speed this up or you''re killing the local economy. Other councils manage it in 8 weeks.', '00000000-0000-4000-a000-000000000007', 15, 'open', '{Efficiency}', 0, '2026-02-02T05:49:22.122Z');
INSERT INTO public.proposals (council_slug, budget_category, title, body, author_id, score, status, labels, comment_count, created_at) VALUES ('dorset-ua', 'central_services', 'How much is spent on consultants vs permanent staff?', 'I''d bet we''re paying double for consultants to do work that permanent employees could do. Publish the numbers and justify it.', '00000000-0000-4000-a000-000000000023', 3, 'open', '{Transparency,Efficiency}', 0, '2026-03-28T00:05:29.999Z');
INSERT INTO public.proposals (council_slug, budget_category, title, body, author_id, score, status, labels, comment_count, created_at) VALUES ('durham', 'central_services', 'Why are council meetings still held at 2pm on a Tuesday?', 'Most people work. Move meetings to 7pm or livestream them properly so residents can actually attend and hold councillors accountable.', '00000000-0000-4000-a000-000000000001', 2, 'open', '{Transparency}', 0, '2026-02-14T01:24:31.727Z');
