INSERT INTO public.proposals (council_slug, budget_category, title, body, author_id, score, status, labels, comment_count, created_at) VALUES ('luton', 'planning', 'Reduce business rates for empty high street shops', 'Half the high street is empty because rates are too high. Temporary rate relief for new businesses would fill them and bring in more tax long-term.', '00000000-0000-4000-a000-000000000001', 24, 'open', '{Efficiency}', 0, '2026-02-11T19:18:30.242Z');
INSERT INTO public.proposals (council_slug, budget_category, title, body, author_id, score, status, labels, comment_count, created_at) VALUES ('medway-towns', 'central_services', 'Why are council meetings still held at 2pm on a Tuesday?', 'Most people work. Move meetings to 7pm or livestream them properly so residents can actually attend and hold councillors accountable.', '00000000-0000-4000-a000-000000000013', 7, 'open', '{Transparency}', 0, '2026-02-03T21:04:32.359Z');
INSERT INTO public.proposals (council_slug, budget_category, title, body, author_id, score, status, labels, comment_count, created_at) VALUES ('medway-towns', 'planning', 'The high street needs rate relief not another consultation', 'Half the shops are empty. How many studies do we need? Temporary rate cuts for independents would fill them. It''s been done in other cities.', '00000000-0000-4000-a000-000000000002', 15, 'open', '{Efficiency}', 0, '2026-03-22T05:51:11.681Z');
INSERT INTO public.proposals (council_slug, budget_category, title, body, author_id, score, status, labels, comment_count, created_at) VALUES ('medway-towns', 'childrens_social_care', 'Agency social workers cost 3x permanent ones — fix retention', 'Permanent staff leave because of impossible caseloads. Then we pay agencies triple to backfill. Fix the root cause instead of throwing money at symptoms.', '00000000-0000-4000-a000-000000000004', 10, 'open', '{Overspend,Efficiency}', 0, '2026-03-30T18:03:46.127Z');
