INSERT INTO public.proposals (council_slug, budget_category, title, body, author_id, score, status, labels, comment_count, created_at) VALUES ('peterborough', 'planning', 'Reduce business rates for empty high street shops', 'Half the high street is empty because rates are too high. Temporary rate relief for new businesses would fill them and bring in more tax long-term.', '00000000-0000-4000-a000-000000000007', 6, 'open', '{Efficiency}', 0, '2026-02-28T03:03:52.166Z');
INSERT INTO public.proposals (council_slug, budget_category, title, body, author_id, score, status, labels, comment_count, created_at) VALUES ('plymouth', 'planning', 'Reduce business rates for empty high street shops', 'Half the high street is empty because rates are too high. Temporary rate relief for new businesses would fill them and bring in more tax long-term.', '00000000-0000-4000-a000-000000000013', 6, 'open', '{Efficiency}', 0, '2026-03-04T18:40:58.607Z');
INSERT INTO public.proposals (council_slug, budget_category, title, body, author_id, score, status, labels, comment_count, created_at) VALUES ('plymouth', 'transport', 'Stop patching potholes — resurface the roads properly', 'The same holes get patched every winter and fall apart by spring. Plymouth is wasting money on temporary fixes. A proper resurfacing programme would be cheaper over 5 years.', '00000000-0000-4000-a000-000000000002', 2, 'open', '{Efficiency}', 0, '2026-03-25T08:51:53.043Z');
INSERT INTO public.proposals (council_slug, budget_category, title, body, author_id, score, status, labels, comment_count, created_at) VALUES ('plymouth', 'planning', 'The high street needs rate relief not another consultation', 'Half the shops are empty. How many studies do we need? Temporary rate cuts for independents would fill them. It''s been done in other cities.', '00000000-0000-4000-a000-000000000023', 21, 'open', '{Efficiency}', 0, '2026-02-04T09:36:17.411Z');
INSERT INTO public.proposals (council_slug, budget_category, title, body, author_id, score, status, labels, comment_count, created_at) VALUES ('plymouth', 'childrens_social_care', 'Agency social workers cost 3x permanent ones — fix retention', 'Permanent staff leave because of impossible caseloads. Then we pay agencies triple to backfill. Fix the root cause instead of throwing money at symptoms.', '00000000-0000-4000-a000-000000000001', 43, 'open', '{Overspend,Efficiency}', 0, '2026-03-15T15:33:41.723Z');
INSERT INTO public.proposals (council_slug, budget_category, title, body, author_id, score, status, labels, comment_count, created_at) VALUES ('plymouth', 'central_services', 'How much is spent on consultants vs permanent staff?', 'I''d bet we''re paying double for consultants to do work that permanent employees could do. Publish the numbers and justify it.', '00000000-0000-4000-a000-000000000009', 7, 'open', '{Transparency,Efficiency}', 0, '2026-02-09T16:56:59.044Z');
