INSERT INTO public.proposals (council_slug, budget_category, title, body, author_id, score, status, labels, comment_count, created_at) VALUES ('stockton-on-tees', 'central_services', 'Agency staff costs are out of control', 'We''re paying agencies 2-3x to fill roles that keep getting vacated. Fix the working conditions so permanent staff stay. It''s basic maths.', '00000000-0000-4000-a000-000000000019', 10, 'open', '{Overspend,Efficiency}', 0, '2026-03-15T23:57:45.829Z');
INSERT INTO public.proposals (council_slug, budget_category, title, body, author_id, score, status, labels, comment_count, created_at) VALUES ('stockton-on-tees', 'education', 'EHCP processing is too slow — streamline the paperwork', 'Families in Stockton-on-Tees wait months because the process has too many handoffs. Cut the bureaucracy, not the staff. Other counties manage it faster with the same budget.', '00000000-0000-4000-a000-000000000008', 2, 'open', '{Efficiency}', 0, '2026-02-22T04:28:31.191Z');
INSERT INTO public.proposals (council_slug, budget_category, title, body, author_id, score, status, labels, comment_count, created_at) VALUES ('stockton-on-tees', 'planning', 'The high street needs rate relief not another consultation', 'Half the shops are empty. How many studies do we need? Temporary rate cuts for independents would fill them. It''s been done in other cities.', '00000000-0000-4000-a000-000000000003', 9, 'open', '{Efficiency}', 0, '2026-03-13T13:28:51.274Z');
INSERT INTO public.proposals (council_slug, budget_category, title, body, author_id, score, status, labels, comment_count, created_at) VALUES ('stockton-on-tees', 'central_services', 'How much is spent on consultants vs permanent staff?', 'I''d bet we''re paying double for consultants to do work that permanent employees could do. Publish the numbers and justify it.', '00000000-0000-4000-a000-000000000001', 30, 'open', '{Transparency,Efficiency}', 0, '2026-02-22T20:10:55.325Z');
INSERT INTO public.proposals (council_slug, budget_category, title, body, author_id, score, status, labels, comment_count, created_at) VALUES ('stockton-on-tees', 'childrens_social_care', 'Agency social workers cost 3x permanent ones — fix retention', 'Permanent staff leave because of impossible caseloads. Then we pay agencies triple to backfill. Fix the root cause instead of throwing money at symptoms.', '00000000-0000-4000-a000-000000000005', 89, 'open', '{Overspend,Efficiency}', 0, '2026-03-01T11:13:30.052Z');
INSERT INTO public.proposals (council_slug, budget_category, title, body, author_id, score, status, labels, comment_count, created_at) VALUES ('stoke-on-trent', 'environmental', 'The broken playground has been "under repair" for a year', 'Kids have nowhere safe to play. The equipment was taped off last spring. What happened to the maintenance budget?', '00000000-0000-4000-a000-000000000012', 3, 'open', '{Efficiency}', 0, '2026-03-01T03:07:01.333Z');
INSERT INTO public.proposals (council_slug, budget_category, title, body, author_id, score, status, labels, comment_count, created_at) VALUES ('stoke-on-trent', 'transport', 'Stop patching potholes — resurface the roads properly', 'The same holes get patched every winter and fall apart by spring. Stoke-on-Trent is wasting money on temporary fixes. A proper resurfacing programme would be cheaper over 5 years.', '00000000-0000-4000-a000-000000000015', 24, 'open', '{Efficiency}', 0, '2026-01-05T12:56:57.616Z');
INSERT INTO public.proposals (council_slug, budget_category, title, body, author_id, score, status, labels, comment_count, created_at) VALUES ('stoke-on-trent', 'planning', 'Reduce business rates for empty high street shops', 'Half the high street is empty because rates are too high. Temporary rate relief for new businesses would fill them and bring in more tax long-term.', '00000000-0000-4000-a000-000000000016', 27, 'open', '{Efficiency}', 0, '2026-03-04T17:50:40.844Z');
