INSERT INTO public.proposals (council_slug, budget_category, title, body, author_id, score, status, labels, comment_count, created_at) VALUES ('wiltshire', 'central_services', 'Agency staff costs are out of control', 'We''re paying agencies 2-3x to fill roles that keep getting vacated. Fix the working conditions so permanent staff stay. It''s basic maths.', '00000000-0000-4000-a000-000000000005', 3, 'open', '{Overspend,Efficiency}', 0, '2026-03-26T08:34:52.570Z');
INSERT INTO public.proposals (council_slug, budget_category, title, body, author_id, score, status, labels, comment_count, created_at) VALUES ('windsor-and-maidenhead', 'planning', 'Reduce business rates for empty high street shops', 'Half the high street is empty because rates are too high. Temporary rate relief for new businesses would fill them and bring in more tax long-term.', '00000000-0000-4000-a000-000000000022', 52, 'open', '{Efficiency}', 0, '2026-02-17T06:20:01.824Z');
INSERT INTO public.proposals (council_slug, budget_category, title, body, author_id, score, status, labels, comment_count, created_at) VALUES ('windsor-and-maidenhead', 'environmental', 'The broken playground has been "under repair" for a year', 'Kids have nowhere safe to play. The equipment was taped off last spring. What happened to the maintenance budget?', '00000000-0000-4000-a000-000000000025', 10, 'open', '{Efficiency}', 0, '2026-02-27T01:59:36.922Z');
INSERT INTO public.proposals (council_slug, budget_category, title, body, author_id, score, status, labels, comment_count, created_at) VALUES ('windsor-and-maidenhead', 'central_services', 'CEO earns £204k — what are the performance targets?', 'If we''re paying this much, there should be published KPIs tied to the salary. What gets measured gets managed.', '00000000-0000-4000-a000-000000000012', 24, 'open', '{Transparency}', 0, '2026-03-18T09:17:21.862Z');
INSERT INTO public.proposals (council_slug, budget_category, title, body, author_id, score, status, labels, comment_count, created_at) VALUES ('windsor-and-maidenhead', 'planning', 'Planning applications shouldn''t take 6 months', 'Local businesses can''t wait half a year for planning permission. Speed this up or you''re killing the local economy. Other councils manage it in 8 weeks.', '00000000-0000-4000-a000-000000000019', 2, 'open', '{Efficiency}', 0, '2026-02-06T00:51:07.632Z');
INSERT INTO public.proposals (council_slug, budget_category, title, body, author_id, score, status, labels, comment_count, created_at) VALUES ('windsor-and-maidenhead', 'environmental', 'Fly-tipping has got worse since you cut tip opening hours', 'The tip closes at 4pm on weekdays. People who work can''t get there. So they dump it. Reopen evenings and you''ll save on cleanup costs.', '00000000-0000-4000-a000-000000000019', 3, 'open', '{Efficiency}', 0, '2026-02-28T21:28:45.013Z');
INSERT INTO public.proposals (council_slug, budget_category, title, body, author_id, score, status, labels, comment_count, created_at) VALUES ('wokingham', 'central_services', 'Why are council meetings still held at 2pm on a Tuesday?', 'Most people work. Move meetings to 7pm or livestream them properly so residents can actually attend and hold councillors accountable.', '00000000-0000-4000-a000-000000000007', 54, 'open', '{Transparency}', 0, '2026-01-21T19:22:40.299Z');
INSERT INTO public.proposals (council_slug, budget_category, title, body, author_id, score, status, labels, comment_count, created_at) VALUES ('wokingham', 'central_services', 'CEO earns £173k — what are the performance targets?', 'If we''re paying this much, there should be published KPIs tied to the salary. What gets measured gets managed.', '00000000-0000-4000-a000-000000000008', 2, 'open', '{Transparency}', 0, '2026-01-30T10:15:04.114Z');
INSERT INTO public.proposals (council_slug, budget_category, title, body, author_id, score, status, labels, comment_count, created_at) VALUES ('wokingham', 'central_services', 'How much is spent on consultants vs permanent staff?', 'I''d bet we''re paying double for consultants to do work that permanent employees could do. Publish the numbers and justify it.', '00000000-0000-4000-a000-000000000022', 1, 'open', '{Transparency,Efficiency}', 0, '2026-03-23T18:57:37.410Z');
