INSERT INTO public.proposals (council_slug, budget_category, title, body, author_id, score, status, labels, comment_count, created_at) VALUES ('york', 'transport', 'Stop patching potholes — resurface the roads properly', 'The same holes get patched every winter and fall apart by spring. York is wasting money on temporary fixes. A proper resurfacing programme would be cheaper over 5 years.', '00000000-0000-4000-a000-000000000014', 56, 'open', '{Efficiency}', 0, '2026-03-11T07:43:21.445Z');
INSERT INTO public.proposals (council_slug, budget_category, title, body, author_id, score, status, labels, comment_count, created_at) VALUES ('york', 'education', 'EHCP processing is too slow — streamline the paperwork', 'Families in York wait months because the process has too many handoffs. Cut the bureaucracy, not the staff. Other counties manage it faster with the same budget.', '00000000-0000-4000-a000-000000000025', 17, 'open', '{Efficiency}', 0, '2026-01-14T14:58:46.756Z');
