INSERT INTO public.proposals (council_slug, budget_category, title, body, author_id, score, status, labels, comment_count, created_at) VALUES ('burnley', 'environmental', 'The bin collection schedule makes no sense', 'Different bins on different weeks, nobody knows which one is which. Simplify it or at least give us a proper app reminder.', '00000000-0000-4000-a000-000000000001', 104, 'open', '{Efficiency}', 0, '2026-02-21T05:42:44.240Z');
INSERT INTO public.proposals (council_slug, budget_category, title, body, author_id, score, status, labels, comment_count, created_at) VALUES ('burnley', 'planning', 'Planning applications shouldn''t take 6 months', 'Local businesses can''t wait half a year for planning permission. Speed this up or you''re killing the local economy. Other councils manage it in 8 weeks.', '00000000-0000-4000-a000-000000000015', 19, 'open', '{Efficiency}', 0, '2026-01-11T05:18:48.390Z');
