INSERT INTO public.proposals (council_slug, budget_category, title, body, author_id, score, status, labels, comment_count, created_at) VALUES ('chorley', 'planning', 'Reduce business rates for empty high street shops', 'Half the high street is empty because rates are too high. Temporary rate relief for new businesses would fill them and bring in more tax long-term.', '00000000-0000-4000-a000-000000000017', 18, 'open', '{Efficiency}', 0, '2026-04-02T00:48:21.745Z');
INSERT INTO public.proposals (council_slug, budget_category, title, body, author_id, score, status, labels, comment_count, created_at) VALUES ('colchester', 'planning', 'Reduce business rates for empty high street shops', 'Half the high street is empty because rates are too high. Temporary rate relief for new businesses would fill them and bring in more tax long-term.', '00000000-0000-4000-a000-000000000013', 11, 'open', '{Efficiency}', 0, '2026-02-08T07:20:07.802Z');
INSERT INTO public.proposals (council_slug, budget_category, title, body, author_id, score, status, labels, comment_count, created_at) VALUES ('colchester', 'central_services', 'Council tax up but services cut — where''s the money going?', 'Fewer bin collections, longer waits, closed offices. The bill went up 5% but nothing got better. Publish a simple breakdown.', '00000000-0000-4000-a000-000000000002', 24, 'open', '{Transparency}', 0, '2026-03-29T08:32:05.595Z');
