INSERT INTO public.proposals (council_slug, budget_category, title, body, author_id, score, status, labels, comment_count, created_at) VALUES ('east-lindsey', 'environmental', 'Half the streetlights on our estate have been out for months', 'Reported it twice. Still dark. This is a safety issue not a nice-to-have. What''s the repair backlog?', '00000000-0000-4000-a000-000000000015', 40, 'open', '{Efficiency}', 0, '2026-02-03T21:06:17.432Z');
INSERT INTO public.proposals (council_slug, budget_category, title, body, author_id, score, status, labels, comment_count, created_at) VALUES ('east-lindsey', 'central_services', 'Council tax up but services cut — where''s the money going?', 'Fewer bin collections, longer waits, closed offices. The bill went up 5% but nothing got better. Publish a simple breakdown.', '00000000-0000-4000-a000-000000000010', 13, 'open', '{Transparency}', 0, '2026-01-31T12:33:56.345Z');
