INSERT INTO public.proposals (council_slug, budget_category, title, body, author_id, score, status, labels, comment_count, created_at) VALUES ('harlow', 'planning', 'Reduce business rates for empty high street shops', 'Half the high street is empty because rates are too high. Temporary rate relief for new businesses would fill them and bring in more tax long-term.', '00000000-0000-4000-a000-000000000019', 13, 'open', '{Efficiency}', 0, '2026-03-07T12:40:05.140Z');
INSERT INTO public.proposals (council_slug, budget_category, title, body, author_id, score, status, labels, comment_count, created_at) VALUES ('hart', 'planning', 'Support local market traders not chain stores', 'The market brings people into town. Give traders reduced pitch fees and better facilities. It costs less than another "regeneration study".', '00000000-0000-4000-a000-000000000006', 3, 'open', '{Efficiency}', 0, '2026-04-01T02:30:26.587Z');
INSERT INTO public.proposals (council_slug, budget_category, title, body, author_id, score, status, labels, comment_count, created_at) VALUES ('hart', 'environmental', 'Fly-tipping has got worse since you cut tip opening hours', 'The tip closes at 4pm on weekdays. People who work can''t get there. So they dump it. Reopen evenings and you''ll save on cleanup costs.', '00000000-0000-4000-a000-000000000012', 3, 'open', '{Efficiency}', 0, '2026-01-11T07:21:20.745Z');
INSERT INTO public.proposals (council_slug, budget_category, title, body, author_id, score, status, labels, comment_count, created_at) VALUES ('hart', 'planning', 'Planning applications shouldn''t take 6 months', 'Local businesses can''t wait half a year for planning permission. Speed this up or you''re killing the local economy. Other councils manage it in 8 weeks.', '00000000-0000-4000-a000-000000000023', 26, 'open', '{Efficiency}', 0, '2026-01-31T03:06:18.911Z');
INSERT INTO public.proposals (council_slug, budget_category, title, body, author_id, score, status, labels, comment_count, created_at) VALUES ('hart', 'environmental', 'The broken playground has been "under repair" for a year', 'Kids have nowhere safe to play. The equipment was taped off last spring. What happened to the maintenance budget?', '00000000-0000-4000-a000-000000000018', 2, 'open', '{Efficiency}', 0, '2026-03-28T03:21:55.335Z');
INSERT INTO public.proposals (council_slug, budget_category, title, body, author_id, score, status, labels, comment_count, created_at) VALUES ('hart', 'planning', 'Reduce business rates for empty high street shops', 'Half the high street is empty because rates are too high. Temporary rate relief for new businesses would fill them and bring in more tax long-term.', '00000000-0000-4000-a000-000000000007', 22, 'open', '{Efficiency}', 0, '2026-03-14T19:33:43.499Z');
