INSERT INTO public.proposals (council_slug, budget_category, title, body, author_id, score, status, labels, comment_count, created_at) VALUES ('lancaster', 'planning', 'Reduce business rates for empty high street shops', 'Half the high street is empty because rates are too high. Temporary rate relief for new businesses would fill them and bring in more tax long-term.', '00000000-0000-4000-a000-000000000009', 3, 'open', '{Efficiency}', 0, '2026-02-12T23:16:53.808Z');
INSERT INTO public.proposals (council_slug, budget_category, title, body, author_id, score, status, labels, comment_count, created_at) VALUES ('lancaster', 'planning', 'Support local market traders not chain stores', 'The market brings people into town. Give traders reduced pitch fees and better facilities. It costs less than another "regeneration study".', '00000000-0000-4000-a000-000000000013', 24, 'open', '{Efficiency}', 0, '2026-01-28T17:27:51.775Z');
