INSERT INTO public.proposals (council_slug, budget_category, title, body, author_id, score, status, labels, comment_count, created_at) VALUES ('north-west-leicestershire', 'central_services', 'Why are council meetings still held at 2pm on a Tuesday?', 'Most people work. Move meetings to 7pm or livestream them properly so residents can actually attend and hold councillors accountable.', '00000000-0000-4000-a000-000000000003', 8, 'open', '{Transparency}', 0, '2026-03-30T04:17:40.949Z');
INSERT INTO public.proposals (council_slug, budget_category, title, body, author_id, score, status, labels, comment_count, created_at) VALUES ('norwich', 'environmental', 'Fly-tipping has got worse since you cut tip opening hours', 'The tip closes at 4pm on weekdays. People who work can''t get there. So they dump it. Reopen evenings and you''ll save on cleanup costs.', '00000000-0000-4000-a000-000000000014', 41, 'open', '{Efficiency}', 0, '2026-04-02T16:02:44.968Z');
INSERT INTO public.proposals (council_slug, budget_category, title, body, author_id, score, status, labels, comment_count, created_at) VALUES ('norwich', 'planning', 'Reduce business rates for empty high street shops', 'Half the high street is empty because rates are too high. Temporary rate relief for new businesses would fill them and bring in more tax long-term.', '00000000-0000-4000-a000-000000000007', 11, 'open', '{Efficiency}', 0, '2026-03-14T14:05:37.833Z');
