INSERT INTO public.proposals (council_slug, budget_category, title, body, author_id, score, status, labels, comment_count, created_at) VALUES ('rother', 'central_services', 'Council tax up but services cut — where''s the money going?', 'Fewer bin collections, longer waits, closed offices. The bill went up 5% but nothing got better. Publish a simple breakdown.', '00000000-0000-4000-a000-000000000017', 113, 'open', '{Transparency}', 0, '2026-03-14T14:14:21.062Z');
INSERT INTO public.proposals (council_slug, budget_category, title, body, author_id, score, status, labels, comment_count, created_at) VALUES ('rother', 'environmental', 'Fly-tipping has got worse since you cut tip opening hours', 'The tip closes at 4pm on weekdays. People who work can''t get there. So they dump it. Reopen evenings and you''ll save on cleanup costs.', '00000000-0000-4000-a000-000000000011', 21, 'open', '{Efficiency}', 0, '2026-02-17T17:12:30.498Z');
INSERT INTO public.proposals (council_slug, budget_category, title, body, author_id, score, status, labels, comment_count, created_at) VALUES ('rother', 'planning', 'Planning applications shouldn''t take 6 months', 'Local businesses can''t wait half a year for planning permission. Speed this up or you''re killing the local economy. Other councils manage it in 8 weeks.', '00000000-0000-4000-a000-000000000007', 38, 'open', '{Efficiency}', 0, '2026-01-10T01:15:53.123Z');
INSERT INTO public.proposals (council_slug, budget_category, title, body, author_id, score, status, labels, comment_count, created_at) VALUES ('rother', 'environmental', 'Half the streetlights on our estate have been out for months', 'Reported it twice. Still dark. This is a safety issue not a nice-to-have. What''s the repair backlog?', '00000000-0000-4000-a000-000000000005', 7, 'open', '{Efficiency}', 0, '2026-02-12T00:33:58.331Z');
INSERT INTO public.proposals (council_slug, budget_category, title, body, author_id, score, status, labels, comment_count, created_at) VALUES ('rugby', 'central_services', 'CEO earns £115k — what are the performance targets?', 'If we''re paying this much, there should be published KPIs tied to the salary. What gets measured gets managed.', '00000000-0000-4000-a000-000000000016', 68, 'open', '{Transparency}', 0, '2026-02-14T07:12:49.568Z');
