INSERT INTO public.proposals (council_slug, budget_category, title, body, author_id, score, status, labels, comment_count, created_at) VALUES ('south-norfolk', 'environmental', 'The bin collection schedule makes no sense', 'Different bins on different weeks, nobody knows which one is which. Simplify it or at least give us a proper app reminder.', '00000000-0000-4000-a000-000000000008', 9, 'open', '{Efficiency}', 0, '2026-02-03T02:48:29.214Z');
INSERT INTO public.proposals (council_slug, budget_category, title, body, author_id, score, status, labels, comment_count, created_at) VALUES ('south-norfolk', 'central_services', 'Council tax up but services cut — where''s the money going?', 'Fewer bin collections, longer waits, closed offices. The bill went up 5% but nothing got better. Publish a simple breakdown.', '00000000-0000-4000-a000-000000000021', 5, 'open', '{Transparency}', 0, '2026-03-30T03:41:23.002Z');
INSERT INTO public.proposals (council_slug, budget_category, title, body, author_id, score, status, labels, comment_count, created_at) VALUES ('south-oxfordshire', 'central_services', 'Why are council meetings still held at 2pm on a Tuesday?', 'Most people work. Move meetings to 7pm or livestream them properly so residents can actually attend and hold councillors accountable.', '00000000-0000-4000-a000-000000000020', 8, 'open', '{Transparency}', 0, '2026-01-10T21:05:55.283Z');
INSERT INTO public.proposals (council_slug, budget_category, title, body, author_id, score, status, labels, comment_count, created_at) VALUES ('south-oxfordshire', 'planning', 'Support local market traders not chain stores', 'The market brings people into town. Give traders reduced pitch fees and better facilities. It costs less than another "regeneration study".', '00000000-0000-4000-a000-000000000011', 10, 'open', '{Efficiency}', 0, '2026-03-06T09:43:11.150Z');
INSERT INTO public.proposals (council_slug, budget_category, title, body, author_id, score, status, labels, comment_count, created_at) VALUES ('south-oxfordshire', 'planning', 'Planning applications shouldn''t take 6 months', 'Local businesses can''t wait half a year for planning permission. Speed this up or you''re killing the local economy. Other councils manage it in 8 weeks.', '00000000-0000-4000-a000-000000000009', 11, 'open', '{Efficiency}', 0, '2026-02-22T08:22:46.314Z');
