INSERT INTO public.proposals (council_slug, budget_category, title, body, author_id, score, status, labels, comment_count, created_at) VALUES ('surrey-heath', 'environmental', 'Fly-tipping has got worse since you cut tip opening hours', 'The tip closes at 4pm on weekdays. People who work can''t get there. So they dump it. Reopen evenings and you''ll save on cleanup costs.', '00000000-0000-4000-a000-000000000019', 9, 'open', '{Efficiency}', 0, '2026-03-18T22:11:46.650Z');
