INSERT INTO public.proposals (council_slug, budget_category, title, body, author_id, score, status, labels, comment_count, created_at) VALUES ('tunbridge-wells', 'environmental', 'Half the streetlights on our estate have been out for months', 'Reported it twice. Still dark. This is a safety issue not a nice-to-have. What''s the repair backlog?', '00000000-0000-4000-a000-000000000008', 35, 'open', '{Efficiency}', 0, '2026-01-23T05:55:01.116Z');
INSERT INTO public.proposals (council_slug, budget_category, title, body, author_id, score, status, labels, comment_count, created_at) VALUES ('tunbridge-wells', 'central_services', 'Council tax up but services cut — where''s the money going?', 'Fewer bin collections, longer waits, closed offices. The bill went up 5% but nothing got better. Publish a simple breakdown.', '00000000-0000-4000-a000-000000000007', 6, 'open', '{Transparency}', 0, '2026-01-21T20:12:00.534Z');
INSERT INTO public.proposals (council_slug, budget_category, title, body, author_id, score, status, labels, comment_count, created_at) VALUES ('tunbridge-wells', 'planning', 'Reduce business rates for empty high street shops', 'Half the high street is empty because rates are too high. Temporary rate relief for new businesses would fill them and bring in more tax long-term.', '00000000-0000-4000-a000-000000000006', 27, 'open', '{Efficiency}', 0, '2026-03-07T21:47:34.170Z');
INSERT INTO public.proposals (council_slug, budget_category, title, body, author_id, score, status, labels, comment_count, created_at) VALUES ('tunbridge-wells', 'central_services', 'CEO earns £165k — what are the performance targets?', 'If we''re paying this much, there should be published KPIs tied to the salary. What gets measured gets managed.', '00000000-0000-4000-a000-000000000012', 5, 'open', '{Transparency}', 0, '2026-03-06T17:52:21.540Z');
