INSERT INTO public.proposals (council_slug, budget_category, title, body, author_id, score, status, labels, comment_count, created_at) VALUES ('west-oxfordshire', 'planning', 'Support local market traders not chain stores', 'The market brings people into town. Give traders reduced pitch fees and better facilities. It costs less than another "regeneration study".', '00000000-0000-4000-a000-000000000021', 33, 'open', '{Efficiency}', 0, '2026-01-05T18:40:08.154Z');
INSERT INTO public.proposals (council_slug, budget_category, title, body, author_id, score, status, labels, comment_count, created_at) VALUES ('west-oxfordshire', 'environmental', 'The broken playground has been "under repair" for a year', 'Kids have nowhere safe to play. The equipment was taped off last spring. What happened to the maintenance budget?', '00000000-0000-4000-a000-000000000012', 4, 'open', '{Efficiency}', 0, '2026-04-02T16:12:35.888Z');
INSERT INTO public.proposals (council_slug, budget_category, title, body, author_id, score, status, labels, comment_count, created_at) VALUES ('west-oxfordshire', 'central_services', 'Why are council meetings still held at 2pm on a Tuesday?', 'Most people work. Move meetings to 7pm or livestream them properly so residents can actually attend and hold councillors accountable.', '00000000-0000-4000-a000-000000000022', 5, 'open', '{Transparency}', 0, '2026-01-28T08:46:42.315Z');
